<?php
namespace App\Models\Customers; use App\Models\Company; use Illuminate\Database\Eloquent\Attributes\Fillable; use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\Relations\BelongsTo;
#[Fillable(['company_id','customer_number_prefix','next_customer_number','default_customer_group_id','birthday_reminder_days_before','inactive_customer_days','lost_customer_days','frequent_return_threshold_count','frequent_return_threshold_days','loyalty_enabled','wallet_enabled','loyalty_points_per_amount','loyalty_amount_per_point','allow_negative_wallet'])] class CustomerSetting extends Model {protected $attributes = ['customer_number_prefix'=>'CUS','next_customer_number'=>1,'birthday_reminder_days_before'=>7,'inactive_customer_days'=>90,'lost_customer_days'=>180,'frequent_return_threshold_count'=>3,'frequent_return_threshold_days'=>90,'loyalty_enabled'=>true,'wallet_enabled'=>true,'allow_negative_wallet'=>false]; protected function casts():array{return ['loyalty_enabled'=>'boolean','wallet_enabled'=>'boolean','allow_negative_wallet'=>'boolean'];} public function company():BelongsTo{return $this->belongsTo(Company::class);} public function defaultGroup():BelongsTo{return $this->belongsTo(CustomerGroup::class,'default_customer_group_id');}}
